-- Seed de recursos de escritura. Punto de vista como destacado por defecto.
-- UUIDs fijos para que el seed sea idempotente (on conflict do update).

on conflict (id) do update set
  titulo = excluded.titulo,
  descripcion = excluded.descripcion,
  ejemplo_label = excluded.ejemplo_label,
  ejemplo_texto = excluded.ejemplo_texto,
  destacado = excluded.destacado,
  orden = excluded.orden,
  updated_at = now();
